-- Fix #1 & #2: AI must use the EXACT status passed in biomarker data (🟢/🟡/🟠/🔴)
-- when choosing the wording "в оптимальном диапазоне / в допустимом диапазоне / выше нормы / ниже нормы".
-- Previously AI was free to interpret the value itself, ignoring the precomputed 7-segment status.
-- Apply to ALL category prompts, since the bug is systemic.

-- Fix #3 (energy only for now): forbid appending "затем контроль уровня" to the Длительность field.

-- =========================
-- ENERGY (also gets fix #3)
-- =========================
UPDATE public.ai_prompt_settings
SET prompt_text = replace(
  prompt_text,
  E'СТРОКА РЕЗУЛЬТАТА\nНачинается с табуляции. Строгий шаблон:\n\n\tВаш [показатель / уровень / значение / индекс] [число] [единицы] находится в [оптимальном диапазоне / ниже оптимального диапазона / выше оптимального порога]. [1–2 предложения интерпретации.]',
  E'СТРОКА РЕЗУЛЬТАТА\nНачинается с табуляции. Строгий шаблон:\n\n\tВаш [показатель / уровень / значение / индекс] [число] [единицы] находится [в оптимальном диапазоне / в допустимом диапазоне (ниже/выше оптимума, но в пределах нормы) / ниже нормы / выше нормы / в зоне риска / в критической зоне]. [1–2 предложения интерпретации.]\n\nКРИТИЧЕСКОЕ ПРАВИЛО — СТАТУС БЕРЁТСЯ ИЗ ДАННЫХ, НЕ ИНТЕРПРЕТИРУЕТСЯ САМОСТОЯТЕЛЬНО:\n\nВ данных {biomarkers} КАЖДЫЙ показатель уже имеет точный статус по 7-сегментной шкале (🟢 ОПТИМАЛЬНО / 🟡 ДОПУСТИМО / 🟠 РИСК / 🔴 КРИТИЧНО). Ты ОБЯЗАН использовать ровно эту классификацию — без права самостоятельно решать, "оптимально" это или нет, на основе близости к границам.\n\nЖЁСТКОЕ СООТВЕТСТВИЕ статуса и формулировки в строке результата:\n— 🟢 ОПТИМАЛЬНО → "находится в оптимальном диапазоне"\n— 🟡 ДОПУСТИМО → "находится в допустимом диапазоне" (можно уточнить: "ниже оптимума, но в пределах нормы" или "выше оптимума, но в пределах нормы" — в зависимости от направления)\n— 🟠 РИСК → "находится ниже нормы" или "находится выше нормы" (в зависимости от направления)\n— 🔴 КРИТИЧНО → "находится в критической зоне ниже/выше нормы"\n\nЗАПРЕТЫ:\n— НИКОГДА не пиши "находится в оптимальном диапазоне", если статус 🟡, 🟠 или 🔴\n— НИКОГДА не пиши "в зоне риска" или "выше/ниже нормы", если статус 🟢 или 🟡\n— НЕ оценивай близость значения к границе на глаз — статус уже посчитан системой и единственно верен'
)
WHERE key = 'category_energy_system';

-- Add fix #3: forbid "затем контроль" in Длительность
UPDATE public.ai_prompt_settings
SET prompt_text = replace(
  prompt_text,
  E'\tДлительность: [срок]',
  E'\tДлительность: [только срок приёма, например "3 месяца" — БЕЗ дополнений типа "затем контроль", "с последующей оценкой", "далее по результатам анализов" и подобных]'
)
WHERE key = 'category_energy_system';

-- =========================
-- Same status-mapping fix for ALL other category prompts
-- =========================
UPDATE public.ai_prompt_settings
SET prompt_text = prompt_text || E'\n\nКРИТИЧЕСКОЕ ПРАВИЛО — СТАТУС БЕРЁТСЯ ИЗ ДАННЫХ, НЕ ИНТЕРПРЕТИРУЕТСЯ САМОСТОЯТЕЛЬНО:\n\nВ данных {biomarkers} КАЖДЫЙ показатель уже имеет точный статус по 7-сегментной шкале (🟢 ОПТИМАЛЬНО / 🟡 ДОПУСТИМО / 🟠 РИСК / 🔴 КРИТИЧНО). Ты ОБЯЗАН использовать ровно эту классификацию — без права самостоятельно решать, "оптимально" это или нет, на основе близости к границам.\n\nЖЁСТКОЕ СООТВЕТСТВИЕ статуса и формулировки в строке результата:\n— 🟢 ОПТИМАЛЬНО → "находится в оптимальном диапазоне"\n— 🟡 ДОПУСТИМО → "находится в допустимом диапазоне" (можно уточнить "ниже оптимума, но в пределах нормы" или "выше оптимума, но в пределах нормы")\n— 🟠 РИСК → "находится ниже нормы" или "находится выше нормы"\n— 🔴 КРИТИЧНО → "находится в критической зоне ниже/выше нормы"\n\nЗАПРЕТЫ:\n— НИКОГДА не пиши "находится в оптимальном диапазоне", если статус 🟡, 🟠 или 🔴\n— НИКОГДА не пиши "в зоне риска" или "выше/ниже нормы", если статус 🟢 или 🟡\n— НЕ оценивай близость значения к границе на глаз — статус уже посчитан системой и единственно верен'
WHERE key IN (
  'category_cardiovascular_system',
  'category_endocrine_system',
  'category_inflammation_system',
  'category_kidneys_system',
  'category_metabolism_system'
)
AND prompt_text NOT LIKE '%КРИТИЧЕСКОЕ ПРАВИЛО — СТАТУС БЕРЁТСЯ ИЗ ДАННЫХ%';